#!/usr/bin/env python3
"""
bootstrap_bead_linker_design.py -- Bead + linker geometry for magnetic pulldown.

Deploys:
  glycan/bead_linker_design.py    -- linker length, entropy, multivalency
  glycan/tests/test_bead_linker.py -- 26 tests

Depends on: bootstrap_click_site_predictor.py (must apply first).
No file conflicts with prior bootstraps.

Test: python -m pytest glycan/tests/test_bead_linker.py -v
"""

import base64, os, sys

FILES = {
    'glycan/bead_linker_design.py': '',
    'glycan/tests/test_bead_linker.py': '',
}


def find_root():
    """Find MABE repo root by looking for core/universal_schema.py."""
    d = os.path.abspath(os.getcwd())
    for _ in range(5):
        if os.path.isfile(os.path.join(d, 'core', 'universal_schema.py')):
            return d
        parent = os.path.dirname(d)
        if parent == d:
            break
        d = parent
    d = os.path.abspath(os.path.join(os.getcwd(), '..'))
    if os.path.isfile(os.path.join(d, 'core', 'universal_schema.py')):
        return d
    print("ERROR: Cannot find MABE repo root (need core/universal_schema.py).")
    print(f"  Searched from: {os.getcwd()}")
    sys.exit(1)


def main():
    root = find_root()
    print(f"MABE root: {root}")
    print()

    for relpath, b64data in FILES.items():
        fullpath = os.path.join(root, relpath)
        os.makedirs(os.path.dirname(fullpath), exist_ok=True)
        content = base64.b64decode(b64data).decode('utf-8')
        with open(fullpath, 'w', encoding='utf-8') as f:
            f.write(content)
        print(f"  written: {relpath}")

    print(f"\nBootstrap complete: {len(FILES)} files written.")
    print("Requires: bootstrap_click_site_predictor.py applied first.")
    print("Run: python -m pytest glycan/tests/test_bead_linker.py -v")


if __name__ == '__main__':
    main()